+/**
+ * Sanitize an SVG DOM to remove potentially dangerous content.
+ * @param {Document} svgDoc - The SVG document to sanitize
+ */
+const sanitizeSvg = function (svgDoc) {
+    // Remove script elements
+    const scripts = svgDoc.querySelectorAll('script');
+    for (const script of scripts) {
+        script.parentNode.removeChild(script);
+    }
+
+    // Remove event handler attributes and dangerous attributes from all elements
+    const allElements = svgDoc.querySelectorAll('*');
+    for (const element of allElements) {
+        const attributesToRemove = [];
+        for (const attr of element.attributes) {
+            const attrName = attr.name.toLowerCase();
+            // Remove event handlers (on*)
+            if (attrName.startsWith('on')) {
+                attributesToRemove.push(attr.name);
+            }
+            // Remove javascript: URLs
+            if ((attrName === 'href' || attrName === 'xlink:href' || attrName === 'src') &&
+                attr.value.trim().toLowerCase().replace(/\s/g, '').startsWith('javascript:')) {
+                attributesToRemove.push(attr.name);
+            }
+        }
+        for (const attrName of attributesToRemove) {
+            element.removeAttribute(attrName);
+        }
+    }
+};
+
