+use anyhow::{anyhow, bail, Context, Result};
+use x509_cert::der::DecodePem;
+
+use crate::{
+    constants::*,
+    quote::QeReport,
+    utils::*,
+};
+
+/// Verify the QE Identity signature against the issuer certificate chain,
+/// and enforce policy constraints (MRSIGNER, ISVPRODID, ISVSVN) on the QE Report.
+pub fn verify_qe_identity(
+    qe_identity: &str,
+    qe_identity_signature: &str,
+    qe_identity_issuer_chain: &str,
+    qe_report: &QeReport,
+    now: u64,
+) -> Result<()> {
+    // Step 1: Parse and validate the certificate chain
+    let certs = extract_certs_from_pem(qe_identity_issuer_chain)
+        .context("Failed to parse QE identity issuer chain")?;
+
+    if certs.is_empty() {
+        bail!("QE identity issuer chain is empty");
+    }
+
+    // Verify the certificate chain up to the Intel root CA
+    verify_certificate_chain(&certs, now)
+        .context("Failed to verify QE identity certificate chain")?;
+
+    // Step 2: Verify the QE Identity signature using the leaf certificate's public key
+    let leaf_cert = &certs[0];
+    let signature_bytes = hex::decode(qe_identity_signature)
+        .context("Failed to decode QE identity signature from hex")?;
+
+    verify_signature(leaf_cert, qe_identity.as_bytes(), &signature_bytes)
+        .context("Failed to verify QE identity signature")?;
+
+    // Step 3: Parse the QE Identity JSON
+    let qe_id: EnclaveIdentityV2 =
+        serde_json::from_str(qe_identity).context("Failed to parse QE identity JSON")?;
+
+    let identity = &qe_id.enclave_identity;
+
+    // Step 4: Enforce MRSIGNER policy constraint
+    let expected_mrsigner = hex::decode(&identity.mrsigner)
+        .context("Failed to decode MRSIGNER from QE identity")?;
+    if qe_report.mrsigner != expected_mrsigner.as_slice() {
+        bail!(
+            "QE Report MRSIGNER mismatch: expected {}, got {}",
+            identity.mrsigner,
+            hex::encode(&qe_report.mrsigner)
+        );
+    }
+
+    // Step 5: Enforce ISVPRODID policy constraint
+    if qe_report.isv_prod_id != identity.isvprodid {
+        bail!(
+            "QE Report ISVPRODID mismatch: expected {}, got {}",
+            identity.isvprodid,
+            qe_report.isv_prod_id
+        );
+    }
+
+    // Step 6: Enforce ISVSVN policy constraint (must be >= minimum)
+    if qe_report.isv_svn < identity.isvsvn {
+        bail!(
+            "QE Report ISVSVN {} is below minimum required {}",
+            qe_report.isv_svn,
+            identity.isvsvn
+        );
+    }
+
+    // Step 7: Check MISCSELECT and ATTRIBUTES against masks
+    let expected_miscselect = u32::from_le_bytes(
+        hex::decode(&identity.miscselect)
+            .context("Failed to decode miscselect")?
+            .try_into()
+            .map_err(|_| anyhow!("Invalid miscselect length"))?,
+    );
+    let miscselect_mask = u32::from_le_bytes(
+        hex::decode(&identity.miscselect_mask)
+            .context("Failed to decode miscselect_mask")?
+            .try_into()
+            .map_err(|_| anyhow!("Invalid miscselect_mask length"))?,
+    );
+    if (qe_report.miscselect & miscselect_mask) != (expected_miscselect & miscselect_mask) {
+        bail!("QE Report MISCSELECT does not match QE Identity policy");
+    }
+
+    let expected_attributes = hex::decode(&identity.attributes)
+        .context("Failed to decode attributes")?;
+    let attributes_mask = hex::decode(&identity.attributes_mask)
+        .context("Failed to decode attributes_mask")?;
+
+    if expected_attributes.len() != 16 || attributes_mask.len() != 16 {
+        bail!("Invalid attributes or attributes_mask length in QE identity");
+    }
+
+    for i in 0..16 {
+        if (qe_report.attributes[i] & attributes_mask[i])
+            != (expected_attributes[i] & attributes_mask[i])
+        {
+            bail!("QE Report ATTRIBUTES does not match QE Identity policy");
+        }
+    }
+
+    // Step 8: Verify QE Identity is within its validity period
+    let issue_date = parse_date(&identity.issue_date)
+        .context("Failed to parse QE identity issue_date")?;
+    let next_update = parse_date(&identity.next_update)
+        .context("Failed to parse QE identity next_update")?;
+
+    if now < issue_date {
+        bail!("QE identity is not yet valid (issue_date is in the future)");
+    }
+    if now > next_update {
+        bail!("QE identity has expired (next_update is in the past)");
+    }
+
+    Ok(())
+}

